var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아. 젠장. 전재산 다 털어도 살 수 있는 게 이 다 식은 치킨 부리또 하나냐.","JPN":"あ。くそ。全財産をかき集めて買えたものが、この冷めたチキンブリトー1個だけだなんて。","ENG":"Ugh, crap. I can't believe this cold chicken burrito is the only thing we can afford.","TWN":"可惡！花光全部的財產只能買到一個涼掉的墨西哥雞肉捲。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무리 생각해도 이 도시 물가는 진짜 미쳤다니까….","JPN":"どう考えても、この街の物価は狂ってるだろ……","ENG":"These city prices are insane...","TWN":"這座城市的物價會不會太誇張……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"미친 건 라이카죠.","JPN":"狂ってるのはライカでしょ。","ENG":"You're the one insane.","TWN":"誇張的是萊卡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"엉? 넌 또 왜 나한테 성질이야?","JPN":"ああ？　今度は八つ当たりか？","ENG":"Huh? What are you getting angry at me for?","TWN":"幹嘛？為什麼又對我發火？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카가 관리부장을 때리지만 않았어도 다른 태스크포스에 들어갈 수 있었어요.","JPN":"ライカが管理部長を殴りさえしなかったら、他のタスクフォースにでも入れてもらえてたわ。","ENG":"We would've been hired by other TASKFORCEs if you hadn't punched the manager.","TWN":"如果你沒打管理部長，我們還有機會加入其他特遣勢力。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 우리도 목표대로 건틀렛에 출전할 수 있었겠죠.","JPN":"そうしたら、私たちもガントレットに出戦するっていう目標を果たせていたはずだったよ。","ENG":"And then we would've entered the Gauntlet, according to plan.","TWN":"那我們就能夠按照原定目標參加聖鎧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"관리부장을 때린 게 내 주먹인 줄 알았냐?","JPN":"私が殴りたくて管理部長を殴ったと思ってるのか？","ENG":"You think it was my hand that punched the manager?","TWN":"你以為我打管理部長是為了我自己嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"틀렸어. 널 향한 측은지심이지.","JPN":"違うね。あんたのことを思ってそうしたんだ。","ENG":"You're wrong. It was the pity I had for you.","TWN":"你錯了，我打他是在替你出氣！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……에휴.","JPN":"……はあ。","ENG":"*Sigh*...","TWN":"……哀。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"한숨 좀 쉬지 마. 누가 애늙은이 아니랄까 봐.","JPN":"ため息つくなよ、ホント年寄りみたいなんだから。","ENG":"Stop sighing. You're such an old soul.","TWN":"別唉聲嘆氣像個老頭子似的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"까짓 거 나가지 뭐. 이 더러운 도시.","JPN":"もういい、出て行ってやる。こんなクズみたいな街。","ENG":"Let's just cut our losses and leave. Who cares about this filthy city, anyway?","TWN":"有什麼了不起的，大不了離開這個骯髒的城市。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 돼요. 못 나가.","JPN":"ダメよ。行かないわ。","ENG":"No. I can't leave.","TWN":"不行，我不能離開。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"사정을 아니까 뭐라 말은 안 하겠는데, 꼬맹아.","JPN":"事情を知ってるから何も言わないけどさ、おこちゃま。","ENG":"I won't be too harsh since I know where you're coming from, kid.","TWN":"我知道你的苦衷，我也就只是發發牢騷而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"네가 그렇게 말 안 듣고 고집 부리니까 욕 먹는 거야.","JPN":"あんたがそんな風に言うこと聞かないで意地張ってるから、悪口言われるんだよ。","ENG":"But your being so stubborn is exactly why people talk behind your back.","TWN":"不過你這麼不聽話又固執，是會挨罵的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"누가 욕하는데요?","JPN":"誰が悪口を言ってるの？","ENG":"Who's talking behind my back?","TWN":"誰會罵我？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내가.","JPN":"私が。","ENG":"Me.","TWN":"我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아악! 이 돌대가리가, 헬멧 쓰고 박치기를 해!?","JPN":"いたたっ！　この石頭、ヘルメット被ったまま頭突きする！？","ENG":"Aaagh! You can't just headbutt people with your helmet on, you knucklehead!","TWN":"哎呀！你這個死腦筋，竟然戴著頭盔撞人！？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뒷골목 부랑자들은 은혜를 모른다더니 다 라이카를 두고 하는 말이었네요.","JPN":"裏路地のホームレスは恩を知らないっていうけど、全部ライカのことだったのね。","ENG":"They say back alley hobos don't know how to be grateful. I guess that includes you.","TWN":"忘恩負義說的就是萊卡你。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"고마운 줄 아세요. 저 아니었으면 아직도 음식물 쓰레기나 파먹고 있었을 걸요.","JPN":"ありがたく思いなさいよね。私に会わなかったら、いまだに生ゴミを漁ってたはずよ。","ENG":"You should be more appreciative. If it weren't for me, you'd still be digging through the dumpster for a meal.","TWN":"你要感謝我吧？要不是我，你現在還在翻垃圾桶裡的食物吃呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여자의 과거는 입에 담지 않는 법이에요. 이 사이코 꼬맹아.","JPN":"女の過去は口にしちゃダメなんです。このサイコガキめ。","ENG":"Didn't anyone teach you that it's bad manners to talk about a woman's past? You psycho kid.","TWN":"怎麼可以隨便翻出女人的黑歷史呢，你這個小瘋子。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래서 어쩌게? 프리랜서로 살려고 해도 일단은 밑천이 있어야 뭘 하지.","JPN":"で、どうする？　フリーランサーでやっていくとしても、とりあえずは資金がないと。","ENG":"So, what now? Even if we want to work freelance, we'll need some kind of start-up money.","TWN":"所以你打算怎麼辦？就算想當自由業，也要有本錢才行。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어른들이 가는 이상한 술집에 라이카를 팔기로 했어요.","JPN":"大人たちが出入りする怪しげなバーに、ライカを売ることにするわ。","ENG":"I've decided to sell you to a sketchy bar that adults go to.","TWN":"我打算把萊卡賣到大人常去的奇怪酒吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아까 보니까 어떤 파렴치한 짓도 잘할 것 같던데요.","JPN":"さっきのやり取りで、どんな破廉恥なことでもうまくやれそうだったから。","ENG":"Based on what you said earlier, it seems like you'll have no problem making money there.","TWN":"我看你剛才那樣，好像什麼丟人的事都難不倒你。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 내가 살집 두툼한 아찌들이랑 노는 동안 넌 자서전이나 써라.","JPN":"ほう。私がデブのおっさんたちと遊んでる間に、あんたは自伝でも書いとけば。","ENG":"Sure. I'll entertain the chubby, middle-aged men while you work on your autobiography.","TWN":"好好好～在我招待那些肥頭大耳的大叔時，你就寫篇自傳。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이것만 안 하면 3대가 놀고 먹는다</color>. 제목 죽이지?","JPN":"<color=#ffd34c>これさえしなければ、3代が上げ膳据え膳</color>。イカしたタイトルだろ？","ENG":"<color=#ffd34c>Avoid this and your children and their children will swim in wealth.</color> Great title, huh?","TWN":"標題是，<color=#ffd34c>想要富過三代，這件事千萬別做！</color>很吸引人吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그으. 여자의 과거는 입에 담지 않는 법이라면서요.","JPN":"くっ。女の過去は口にしないんじゃなかったの？","ENG":"Rgh. You were the one who said it's bad manners to talk about a woman's past.","TWN":"唔，你不是說不可以翻出女人的黑歷史嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"네가 여자냐. 꼬맹이지.","JPN":"誰が女だよ。おこちゃまだろ。","ENG":"You're not a woman. You're a kid.","TWN":"你算女人嗎？你只是個小鬼。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 시민증 뺏기기 싫으면, 아르바이트든 뭐든 일자리부터 구해야 돼.","JPN":"とにかく、市民証奪われたくなかったら、バイトでもなんでもいいから職場を探さないと。","ENG":"Anyway, if we want to keep our citizen status, we gotta find a job.","TWN":"總之不想被吊銷市民證的話，就算是打工也好，要先找個工作才行。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 전까지는 상자로 집을 쌓든 성을 쌓든 해서 버티고….","JPN":"それまではダンボールで家を作るか城を作るかして持ちこたえて……","ENG":"Until then, I guess we'll just make a cardboard house or castle to li–","TWN":"在那之前，今天就用紙箱子將就一下……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐예요? 이거 지진 아니에요?","JPN":"な、なに？　これ、地震じゃない？","ENG":"W-what was that? Is this an earthquake?","TWN":"怎，怎麼回事？是地震嗎？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니. 그런 간단한 게 아닌 것 같아.","JPN":"いや。そんな易しいもんじゃなさそうだ。","ENG":"No. I don't think it's that simple.","TWN":"不，好像不是單純的地震。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저기 봐.","JPN":"あそこを見ろ。","ENG":"Look.","TWN":"你看那邊。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저건…. 대균열? 예전에도 저렇게 빛난 적이 있었어요?","JPN":"あれは……大亀裂？　前にもあんな風に光ったことがあったっけ？","ENG":"That's... the Grand Dimension Crevice? Has it ever glowed like that before?","TWN":"那是……大峽谷？以前也有過那樣發光的時候嗎？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"한 번도 없어. 적어도 내가 아는 한에는.","JPN":"一度もない。少なくとも私が知ってる限りは。","ENG":"Never. At least, to my knowledge.","TWN":"從來沒有，至少據我所知是沒有過。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래요……?","JPN":"そう……？","ENG":"Is that so...?","TWN":"是嗎……？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니, 학교 다닐 때 배웠어요.","JPN":"そういえば、学校にいた頃習ったわ。","ENG":"Come to think of it, there's something I learned at school.","TWN":"我想起來了，上學的時候學過。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대균열이 처음 나타났을 때는 지금과 비교할 수 없이 밝았다고.","JPN":"大亀裂が初めて現れた時は、今とは比べ物にならないくらい明るかったって。","ENG":"That, when the Grand Dimension Crevice first appeared, it was unbelievably bright.","TWN":"大峽谷第一次出現的時候特別亮，根本不是現在可以比的。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"낮밤을 구분할 수 없을 만큼 환해졌다가, 하늘도 땅도 침식체로 온통 뒤덮였다고…….","JPN":"昼夜もわからないくらい明るくなって、空も地上も侵食体だらけになったって……","ENG":"It was so bright that you couldn't tell night from day. And then, the sky and ground were covered with C.O.s...","TWN":"亮到難以區分白天和夜晚的程度，那時天上地下到處都是侵蝕體……"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래? 왜 나는 들은 적이 없냐.","JPN":"ふうん？　聞いたことないな。","ENG":"Really? I've never heard of that.","TWN":"是嗎？為什麼我沒聽說過？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……라이카, 세상이 망하는 건 아니겠죠? 지금 망하면 안 되는데.","JPN":"……ライカ、まさか世界が滅亡するんじゃないよね？　今滅亡されると困るんだけど。","ENG":"...Laika, do you think this is the end of the world? I really don't want it to.","TWN":"……萊卡，世界不會要毀滅了吧？現在毀滅可不行。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"글쎄. 차라리 제대로 한 번 망하는 것도 나쁘진 않을 것 같은데.","JPN":"さあ？　いっそのこと完全に滅びてみるのも悪くないと思うけどね。","ENG":"I don't know, but it wouldn't be the worst for it to end.","TWN":"誰知道呢，不過世界要是真的毀滅了好像也不錯。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"난 항상 망하다 말아서 세상이 이 모양 이 꼴이라고 생각했거든.","JPN":"私は常々、滅亡が中途半端だから世界がこの様なんだと思ってたから。","ENG":"I've always thought this world is like this because it never goes through with the \\"ending\\" part.","TWN":"我一直覺得就是因為要死不活的，這個世界才會這麼糟糕。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 펠리세트.","JPN":"おい、フェリセット。","ENG":"Hey, Félicette.","TWN":"喂，費莉塞特。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"갑자기 왜 불러요?","JPN":"なによ、急に。","ENG":"What?","TWN":"幹嘛突然叫我？"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어차피 망할 것 같으면…….","JPN":"どうせ滅ぶんなら……","ENG":"If the world's ending anyway...","TWN":"反正這個世界也要完蛋了……"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 전에 한탕 크게 벌여 볼래?","JPN":"その前に、大儲けしてみないか？","ENG":"Wanna go out with a bang?","TWN":"在那之前要不要跟我幹一票大的？"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};